```ts
function isPalindromeNumber(x: number): boolean {
  // Negative numbers are not palindromes.
  if (x < 0) return false;
  // Numbers ending in 0 are not palindromes unless the number is 0.
  if (x % 10 === 0 && x !== 0) return false;

  let reverted = 0;
  // Reverse digits until reverted has at least half the digits of x
  while (x > reverted) {
    reverted = reverted * 10 + (x % 10);
    x = Math.floor(x / 10);
  }

  // For even length numbers: x === reverted
  // For odd length numbers: x === Math.floor(reverted / 10) (middle digit ignored)
  return x === reverted || x === Math.floor(reverted / 10);
}
```

