Here's a small, robust TypeScript implementation that deep-clones values including plain objects, arrays, Date, RegExp, Map, Set and handles circular references. It preserves object prototype and property descriptors (so non-enumerable props and getters/setters are preserved). Functions and symbols are returned as-is.

function deepClone<T>(value: T): T {
  const visited = new WeakMap<object, any>();

  function _clone<T>(val: T): T {
    // primitives & functions
    if (val === null || typeof val !== 'object') return val;

    // Already cloned (circular refs)
    if (visited.has(val as any)) {
      return visited.get(val as any);
    }

    // Date
    if (val instanceof Date) {
      return new Date(val.getTime()) as any;
    }

    // RegExp
    if (val instanceof RegExp) {
      const re = new RegExp(val.source, val.flags);
      (re as any).lastIndex = (val as any).lastIndex;
      return re as any;
    }

    // Map
    if (val instanceof Map) {
      const result = new Map();
      visited.set(val as any, result);
      for (const [k, v] of val as any as Map<any, any>) {
        result.set(_clone(k), _clone(v));
      }
      return result as any;
    }

    // Set
    if (val instanceof Set) {
      const result = new Set();
      visited.set(val as any, result);
      for (const v of val as any as Set<any>) {
        result.add(_clone(v));
      }
      return result as any;
    }

    // Array
    if (Array.isArray(val)) {
      const arr: any[] = [];
      visited.set(val as any, arr);
      (val as any as any[]).forEach((item, i) => {
        arr[i] = _clone(item);
      });
