    let value = parseUnary();
    skipSpace();
    while (s[i] === '*' || s[i] === '/') {
      const op = s[i++];
      const rhs = parseUnary();
      if (op === '*') value *= rhs;
      else value /= rhs;
      skipSpace();
    }
    return value;
  }

  // Unary -> '-' Unary | '+' Unary | Primary
  function parseUnary() {
    skipSpace();
    if (s[i] === '+') { i++; return parseUnary(); }
    if (s[i] === '-') { i++; return -parseUnary(); }
    return parsePrimary();
  }

  // Primary -> number | '(' Expression ')'
  function parsePrimary() {
    skipSpace();
    if (s[i] === '(') {
      i++; // consume '('
      const val = parseExpression();
      skipSpace();
      if (s[i] !== ')') throw new Error("Expected ')' at position " + i);
      i++; // consume ')'
      return val;
    }
    return parseNumber();
