    const startNode = this._findNode(prefix);
    if (!startNode) return [];

    const results = [];

    // If the prefix itself is a word, include it first (it will also be in sorted order below,
    // but including it explicitly is slightly more efficient and deterministic).
    if (startNode.isWord) {
      results.push(prefix);
      if (results.length >= limit) return results;
    }

    // DFS collecting words; children are visited in lexicographic order to ensure results are sorted.
    const collect = (node, path) => {
      if (results.length >= limit) return; // early exit
      const keys = Array.from(node.children.keys()).sort();
      for (const ch of keys) {
        if (results.length >= limit) break;
        const child = node.children.get(ch);
        const newWord = path + ch;
        if (child.isWord) {
          results.push(newWord);
          if (results.length >= limit) break;
        }
        collect(child, newWord);
      }
    };

    collect(startNode, prefix);
    return results;
  }

  // Helper: return the node for the given prefix (or null if missing)
  _findNode(prefix) {
    let node = this.root;
    for (const ch of prefix) {
      if (!node.children.has(ch)) return null;
      node = node.children.get(ch);
    }
    return node;
  }
}

