- on(event, listener)
- off(event, listener)
- once(event, listener)
- emit(event, ...args)
- wildcard '*' listeners fire for all events (they receive the event name as the first argument)
- off removes only the specific listener instance (and will remove a once-wrapper if you call off with the original listener)
- once listeners are automatically removed after being invoked once
- preserves insertion order and allows duplicate additions (same function can be added multiple times as separate instances)

TypeScript code:

```ts
type EventKey = string | number | symbol;

export class TypedEventEmitter<Events extends Record<EventKey, any[]>> {
  private listeners = new Map<EventKey | '*', Function[]>();

  // ---- Overloads ----
  on<E extends keyof Events>(event: E, listener: (...args: Events[E]) => void): this;
  on(event: '*', listener: (event: keyof Events, ...args: any[]) => void): this;

  once<E extends keyof Events>(event: E, listener: (...args: Events[E]) => void): this;
  once(event: '*', listener: (event: keyof Events, ...args: any[]) => void): this;

  off<E extends keyof Events>(event: E, listener: (...args: Events[E]) => void): this;
  off(event: '*', listener: (event: keyof Events, ...args: any[]) => void): this;

  emit<E extends keyof Events>(event: E, ...args: Events[E]): void;

  // ---- Implementation ----
  on(event: any, listener: Function): this {
    const arr = this.listeners.get(event) ?? [];
    arr.push(listener);
    this.listeners.set(event, arr);
    return this;
  }

  once(event: any, listener: Function): this {
    // wrapper removes itself before invoking original listener
    const wrapped: Function = (...args: any[]) => {
      // remove the wrapper (so it's called only once)
      this.off(event, wrapped);
      // call the original listener
      listener(...args);
    };
    // allow off(original) to find and remove the wrapper as well
    (wrapped as any).__original = listener;
    return this.on(event, wrapped);
  }

  off(event: any, listener: Function): this {
    const arr = this.listeners.get(event);
    if (!arr || arr.length === 0) return this;

    // remove only the first matching instance
    for (let i = 0; i < arr.length; i++) {
      const item = arr[i] as any;
      if (item === listener || item.__original === listener) {
        arr.splice(i, 1);
        break;
      }
    }

    if (arr.length === 0) this.listeners.delete(event);
    else this.listeners.set(event, arr);

    return this;
  }

  emit(event: keyof Events, ...args: any[]): void {
    // call listeners for the specific event
    const arr = this.listeners.get(event);
    if (arr && arr.length) {
      // copy to protect against changes during iteration
      const copy = arr.slice();
      for (const fn of copy) {
        (fn as Function)(...args);
      }
    }

    // call wildcard listeners with (event, ...args)
    const wc = this.listeners.get('*');
    if (wc && wc.length) {
      const copy = wc.slice();
      for (const fn of copy) {
        (fn as Function)(event, ...args);
      }
    }
  }
}
```

