Here's a TypeScript implementation of a **TypedEventEmitter** class with the requested features:

- **on(event, listener)**: Registers a listener for an event.
- **off(event, listener)**: Removes a specific listener for an event.
- **once(event, listener)**: Registers a listener that is called at most once.
- **emit(event, ...args)**: Emits an event, calling all listeners for that event and all wildcard (`'*'`) listeners.
- **'*' wildcard**: Listeners registered for `'*'` are called for every event, receiving the event name as the first argument.
- **off** removes only the specific listener instance.
- **once** listeners auto-remove after one call.

### TypeScript Implementation

```typescript
type Listener<Args extends any[]> = (...args: Args) => void;
type WildcardListener = (event: string, ...args: any[]) => void;

type EventMap = Record<string, any[]>;

class TypedEventEmitter<Events extends EventMap> {
  private listeners: { [K in keyof Events]?: Set<Listener<Events[K]>> } = {};
  private wildcardListeners: Set<WildcardListener> = new Set();

  on<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void;
  on(event: '*', listener: WildcardListener): void;
  on(event: string, listener: (...args: any[]) => void): void {
    if (event === '*') {
      this.wildcardListeners.add(listener as WildcardListener);
    } else {
      if (!this.listeners[event]) {
        this.listeners[event] = new Set();
      }
      this.listeners[event]!.add(listener as Listener<any[]>);
    }
  }

  off<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void;
  off(event: '*', listener: WildcardListener): void;
  off(event: string, listener: (...args: any[]) => void): void {
    if (event === '*') {
      this.wildcardListeners.delete(listener as WildcardListener);
    } else {
      this.listeners[event]?.delete(listener as Listener<any[]>);
    }
  }

  once<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void;
  once(event: '*', listener: WildcardListener): void;
  once(event: string, listener: (...args: any[]) => void): void {
    const self = this;
    function onceListener(this: any, ...args: any[]) {
      self.off(event, onceListener);
      (listener as any).apply(this, args);
    }
    this.on(event, onceListener);
  }

  emit<K extends keyof Events>(event: K, ...args: Events[K]): void;
  emit(event: string, ...args: any[]): void {
    // Call event listeners
    (this.listeners[event] ? Array.from(this.listeners[event]!) : []).forEach(listener => {
      listener(...args);
    });
    // Call wildcard listeners
    this.wildcardListeners.forEach(listener => {
      listener(event, ...args);
    });
  }
}
