Below is the implementation of the `TypedEventEmitter` class in JavaScript. This class supports the `on`, `off`, `once`, and `emit` methods, as well as a wildcard `'*'` listener that fires for all events.

```javascript
class TypedEventEmitter {
  constructor() {
    this.listeners = new Map(); // Map to store event listeners
    this.wildcardListeners = new Set(); // Set to store wildcard listeners
  }

  // Add a listener for a specific event
  on(event, listener) {
    if (event === '*') {
      this.wildcardListeners.add(listener);
    } else {
      if (!this.listeners.has(event)) {
        this.listeners.set(event, new Set());
      }
      this.listeners.get(event).add(listener);
    }
  }

  // Remove a specific listener for a specific event
  off(event, listener) {
    if (event === '*') {
      this.wildcardListeners.delete(listener);
    } else {
      const eventListeners = this.listeners.get(event);
      if (eventListeners) {
        eventListeners.delete(listener);
        if (eventListeners.size === 0) {
          this.listeners.delete(event);
        }
      }
    }
  }

  // Add a listener that will be called only once
  once(event, listener) {
    const wrapper = (...args) => {
      this.off(event, wrapper); // Remove the listener after it's called
      listener(...args); // Call the original listener
    };
    this.on(event, wrapper);
  }

  // Emit an event, calling all relevant listeners
  emit(event, ...args) {
    // Call specific event listeners
    const eventListeners = this.listeners.get(event);
    if (eventListeners) {
      for (const listener of eventListeners) {
        listener(...args);
      }
    }

    // Call wildcard listeners
    for (const wildcardListener of this.wildcardListeners) {
      wildcardListener(event, ...args);
    }
  }
}

