class TypedEventEmitter<Events extends Record<string, any[]>> {
  private listeners = new Map<keyof Events | '*', Array<{ fn: Function; original: Function }>>()

  on<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this
  on(event: '*', listener: (event: keyof Events, ...args: unknown[]) => void): this
  on(event: keyof Events | '*', listener: Function) {
    const list = this.listeners.get(event)
    const entry = { fn: listener, original: listener }
    if (list) list.push(entry)
    else this.listeners.set(event, [entry])
    return this
  }

  off<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this
  off(event: '*', listener: (event: keyof Events, ...args: unknown[]) => void): this
  off(event: keyof Events | '*', listener: Function) {
    const list = this.listeners.get(event)
    if (!list) return this

    const idx = list.findIndex(
      entry => entry.fn === listener || entry.original === listener
    )
    if (idx === -1) return this

    list.splice(idx, 1)
    if (list.length === 0) this.listeners.delete(event)
    return this
  }

  once<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this
  once(event: '*', listener: (event: keyof Events, ...args: unknown[]) => void): this
  once(event: keyof Events | '*', listener: Function) {
    const wrapper = (...args: unknown[]) => {
      this.off(event, wrapper)
      listener(...args)
    }

    const list = this.listeners.get(event)
    const entry = { fn: wrapper, original: listener }
    if (list) list.push(entry)
    else this.listeners.set(event, [entry])
    return this
  }

  emit<K extends keyof Events>(event: K, ...args: Events[K]): void {
    const entries = this.listeners.get(event)
    if (entries) {
      for (const { fn } of [...entries]) {
        fn(...args)
      }
    }

    const wildcards = this.listeners.get('*')
    if (wildcards) {
      for (const { fn } of [...wildcards]) {
        fn(event, ...args)
      }
    }
  }
}
